// // When memread is high, select ALU output; when memread is low, choose memory output
module top_module( alu_v, mem_v, memread, 
            reg_write_data);input [31:0] alu_v, mem_v;
    input memread;
    output [31:0] reg_write_data;

    assign reg_write_data = (memread == 0) ? alu_v : mem_v;

endmodule
